Templates/Monthly.content:
&lt;&lt; [[&lt;% tp.date.now(“YYYY-[M]MM”, “P-1M”) %&gt;]] | [[&lt;% tp.date.now(“YYYY-[M]MM”, “P+1M”) %&gt;]] &gt;&gt;
&lt;% tp.file.cursor(0) %&gt;
Notes Created This Month
TABLE aliases
FROM &quot;Journal&quot;
WHERE file.day.year = number(substring(this.file.name, 0, 4))
AND dateformat(date(file.name), &quot;yyyy-MM&quot;) = replace(this.file.name, &quot;M&quot;, &quot;&quot;)
SORT file.day

TABLE WITHOUT ID file.day.weekyear AS Week
FROM &quot;Journal/Daily&quot;
WHERE file.day.year = number(substring(this.file.name, 0, 4))
AND dateformat(date(file.name), &quot;yyyy-MM&quot;) = replace(this.file.name, &quot;M&quot;, &quot;&quot;)
SORT file.day

Templates/Weekly.content:
&lt;&lt; [[&lt;% moment(tp.file.title, “YYYY-[W]W”).subtract(1, “weeks”).format(“YYYY-[W]W”) %&gt;]] | [[&lt;% moment(tp.file.title, “YYYY-[W]W”).add(1, “weeks”).format(“YYYY-[W]W”) %&gt;]] &gt;&gt;
&lt;% tp.file.cursor(0) %&gt;
Notes Created This Week
TABLE highlights
FROM &quot;Journal/Daily&quot;
WHERE file.day.year = number(substring(string(this.file.name), 0, 4))
AND file.day.weekyear = number(substring(string(this.file.name), 6, 8))
SORT file.day

